// 1301 Number of Paths with Max Score
// https://leetcode.com/problems/number-of-paths-with-max-score/description/
// Difficulty: Hard
// Time Taken: 02:12;55

// I don't understand the path transition function


public class Solution {
  public const int MOD = 1_000_000_007;
  public int[] PathsWithMaxScore(IList<string> board) {
    int[] answer = new int[2];
    int rows = board.Count;
    int cols = board[0].Length;
    int[][] grid = new int[rows][];
    for (int row = 0; row < rows; row++) {
      grid[row] = new int[cols];
      for (int col = 0; col < cols; col++) {
        if (board[row][col] == 'S') {
          grid[row][col] = 0;
        } else if (board[row][col] == 'E') {
          grid[row][col] = 0;
        } else if (board[row][col] == 'X') {
          grid[row][col] = -1;
        } else {
          grid[row][col] = board[row][col] - '0';
        }
      }
    }

    int[][] score = new int[rows][];
    bool[][] reach = new bool[rows][];
    int[][] paths = new int[rows][];
    for (int row = 0; row < rows; row++) {
      score[row] = new int[cols];
      reach[row] = new bool[cols];
      paths[row] = new int[cols];
    }


    for (int row = 0; row < rows; row++) {
      for (int col = 0; col < cols; col++) {
        if (grid[row][col] == -1) {
          reach[row][col] = false;
        } else {
          bool up = (row - 1 >= 0) ? reach[row - 1][col] : false;
          bool left = (col - 1 >= 0) ? reach[row][col - 1] : false;
          bool up_left = (row - 1 >= 0 && col - 1 >= 0) ? reach[row - 1][col - 1] : false;
          bool is_end = row == 0 && col == 0;
          reach[row][col] = up || left || up_left || is_end;
        }
      }
    }

    score[0][0] = 0;
    for (int row = 0; row < rows; row++) {
      for (int col = 0; col < cols; col++) {
        int upScore = 0;
        int leftScore = 0;
        int upLeftScore = 0;
        if (row - 1 >= 0 && reach[row - 1][col]) {
          upScore = score[row - 1][col] + grid[row][col];
        }
        if (col - 1 >= 0 && reach[row][col - 1]) {
          leftScore = score[row][col - 1] + grid[row][col];
        }
        if (row - 1 >= 0 && col - 1 >= 0 && reach[row - 1][col - 1]) {
          upLeftScore = score[row - 1][col - 1] + grid[row][col];
        }
        score[row][col] = Math.Max(upLeftScore, Math.Max(upScore, leftScore));
      }
    }

    paths[0][0] = 1;
    for (int row = 0; row < rows; row++) {
      for (int col = 0; col < cols; col++) {
        if (row == 0 && col == 0) { continue; }
        if (!reach[row][col]) { continue; }

        int currentScore = score[row][col] - grid[row][col];
        // up
        if (row - 1 >= 0 && reach[row - 1][col]) {
          if (currentScore == score[row - 1][col]) {
            paths[row][col] = (paths[row][col] + paths[row - 1][col]) % MOD;
          }
        }
        // left
        if (col - 1 >= 0 && reach[row][col - 1]) {
          if (currentScore == score[row][col - 1]) {
            paths[row][col] = (paths[row][col] + paths[row][col - 1]) % MOD;
          }
        }
        // up_left
        if (row - 1 >= 0 && col - 1 >= 0 && reach[row - 1][col - 1]) {
          if (currentScore == score[row - 1][col - 1]) {
            paths[row][col] = (paths[row][col] + paths[row - 1][col - 1]) % MOD;
          }
        }
      }
    }

    int maxScore = score[rows - 1][cols - 1];
    int numPaths = paths[rows - 1][cols - 1];
    return [maxScore, numPaths];
  }
}


